  const _missingCostBasisGuardActive = _syntheticLotsDetected && _earlyRealBackedClosedLots === 0 && !_adminOverrideUsed
  const _syntheticTargetsTooManyForDefaultRecovery = _syntheticLotTokenTargets.length > 2

